-- CREATE POLICY "auth_insert"  ON partners FOR INSERT TO authenticated WITH CHECK (true);
-- CREATE POLICY "auth_update"  ON partners FOR UPDATE TO authenticated USING (true);
-- CREATE POLICY "auth_delete"  ON partners FOR DELETE TO authenticated USING (true);
